mapper.delete:
		/*
             SQL ID : MutEvalGradeDAO.delMutEvalGrade
             	설  명 : 평가 등급 삭제
        */
		DELETE FROM MTL_EVL_GRD
		WHERE ASMT_MTL_EVL_RSLT_ID = #{evalCd}
		AND QSTN_ID IN

            #{item}

mapper.insert:
		/*
             SQL ID : MutEvalGradeDAO.insertMutEvalGrade
             	설  명 : 평가 등급 등록
        */
        INSERT INTO MTL_EVL_GRD (
        	  GRDCD
			, ASMT_MTL_EVL_RSLT_ID
			, QSTN_ID
			, MTL_EVL_GRD_TTL
			, MTL_EVL_GRD_CTS
			, MTL_EVL_MRK_GRDCD
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
        ) VALUES (
        	  #{gradeCd}
        	, #{evalCd}
        	, #{qstnCd}
        	, #{gradeTitle}
        	, #{gradeCts}
        	, #{gradeScore}
        	, #{rgtrId}
        	, FN_DTTM()
        	, #{mdfrId}
        	, FN_DTTM()
        )
